def _debug():
    import json
    from pathlib import Path
    from typing_extensions import get_type_hints, get_origin, get_args, is_typeddict

    spec = json.load(open("./projects/bluecat/openapi2.json"))

    body = ""

    for name, schema in spec["components"]["endpoint_schemas"].items():
        if "PostRequestBody" in name:
            related_schema_name = name.replace("PostRequestBody", "")
            action = "post"
        else:
            related_schema_name = name.replace("PutRequestBody", "")
            action = "put"
        related_schema = spec["components"]["schemas"].get(related_schema_name)
        assert related_schema, f"Schema {related_schema_name} not found in components.schemas"
        args_list = []
        fn_body = []
        required_fields = set(schema.get("required", []))
        props = related_schema.get("properties", {})
        if not props:
            if len(related_schema.get("allOf", [])) == 2:
                inherited_schema_name = related_schema["allOf"][0]["$ref"].rpartition("/")[2]
                base_props = spec["components"]["schemas"][inherited_schema_name].get("properties", {})
                props = related_schema.get("allOf", [{}])[-1].get("properties", {}) | base_props
            elif len(related_schema.get("allOf", [])) == 1:
                props = related_schema.get("allOf", [{}])[-1].get("properties", {})
            else:
                raise Exception(f"Schema {related_schema_name} has no properties and no allOf")
        if schema.get("properties", {}):
            # There are extra props in the schema that are not in the related schema
            props = schema["properties"] | props
        for field in required_fields.copy():
            if field not in props:
                raise Exception(f"Field {field} not found in schema {related_schema_name}")
            related_schema_typedict = globals().get(related_schema_name)
            if related_schema_typedict is None:
                raise Exception(f"TypedDict for {related_schema_name} not found in globals")
            type_hint = get_type_hints(related_schema_typedict).get(field, None)

            if type_hint is None:
                # this may be an extra field in the schema that is not in the related schema
                if "type" in schema["properties"][field]:
                    type_hint = schema["properties"][field]["type"]
                    if type_hint == "string":
                        type_hint = str
                    elif type_hint == "integer":
                        type_hint = int
                    elif type_hint == "boolean":
                        type_hint = bool
                    else:
                        raise Exception(f"Type hint for field {field} not found in schema {related_schema_name}")
                elif "$ref" in schema["properties"][field]:
                    type_hint = schema["properties"][field]["$ref"].rpartition("/")[2]
                    type_hint = globals().get(type_hint, None)
                    if type_hint is None:
                        raise Exception(f"Type hint for field {field} not found in globals")
                else:
                    raise Exception(f"Type hint for field {field} not found in schema {related_schema_name}")
            # shave off NotRequired and ReadOnly, they don't make sense in this context
            if get_origin(type_hint) is NotRequired:
                type_hint = get_args(type_hint)[0]
            if get_origin(type_hint) is ReadOnly:
                type_hint = get_args(type_hint)[0]
            if get_origin(type_hint) is Literal and len(get_args(type_hint)) == 1:
                fn_body.append(f"kwargs = {{'{field}': {get_args(type_hint)[0]!r}, **kwargs}}")
                required_fields.remove(field)
            elif get_origin(type_hint) is list:
                if len(get_args(type_hint)) == 1:
                    item_type = get_args(type_hint)[0]
                    if is_typeddict(item_type) or isinstance(item_type, (str, int, bool)):
                        item_type_name = item_type.__name__  # pyright: ignore[reportAttributeAccessIssue]
                        args_list.append(f"{field}: list[{item_type_name}]")
                    else:
                        type_hint = (
                            str(type_hint)
                            .replace("typing.", "")
                            .replace("builtins.", "")
                            .replace("typing_extensions.", "")
                        )
                        args_list.append(f"{field}: {type_hint}")
                else:
                    raise NotImplementedError("List type hints are not supported")
            elif type_hint is str:
                args_list.append(f"{field}: str")
            elif type_hint is int:
                args_list.append(f"{field}: int")
            elif type_hint is bool:
                args_list.append(f"{field}: bool")
            elif is_typeddict(type_hint):
                item_type = type_hint.__name__
                args_list.append(f"{field}: {item_type}")
            else:
                type_hint = (
                    str(type_hint).replace("typing.", "").replace("builtins.", "").replace("typing_extensions.", "")
                )
                args_list.append(f"{field}: {type_hint}")

        fn_name = f"{related_schema_name.lower()}_{action}"
        args_list.append(f"**kwargs: Unpack[{related_schema_name}]   # pyright: ignore[reportGeneralTypeIssues]")
        args_list = ",\n    ".join(args_list)
        defn = f"def {fn_name}(\n    {args_list}\n) -> {related_schema_name}:"
        kwargs_stmt = [f"'{field}': {field}" for field in required_fields]
        kwargs_stmt = ", ".join(kwargs_stmt)
        kwargs_stmt = f"{kwargs_stmt}, **kwargs" if kwargs_stmt else "**kwargs"
        defn += f"\n    kwargs = {{{kwargs_stmt}}}  # pyright: ignore[reportGeneralTypeIssues]"
        for s in fn_body:
            defn += f"\n    {s}"
        defn += "\n    return kwargs"
        defn += "\n\n"
        body += defn
    Path("projects/bluecat/test2.py").write_text(body)
